<template>
  <VDialog v-model="showDialog" width="auto" @after-leave="onAfterLeave">
    <VCard :prepend-icon="mdiIcon.mdiCash" :title="props.title || 'Pembayaran'" width="500">
      <VCardText class="pa-5">
        <VForm ref="paymentForm" lazy-validation>
          <VTextField label="Total" readonly>{{ props.total }}</VTextField>
          <VTextField
            v-model="paid"
            :readonly="selectedTipe.value != 'cash'"
            label="Bayar"
          ></VTextField>
          <VTextField v-if="selectedTipe.value == 'cash'" label="Kembalian" readonly>{{
            Kembalian
          }}</VTextField>
          <VCombobox
            v-model="selectedTipe"
            :items="tipePayments"
            :return-object="true"
            clearable
            item-title="label"
            item-value="value"
            label="Tipe Pembayaran"
            variant="outlined"
          >
          </VCombobox>
          <VTextField v-if="showRef" label="ref"> </VTextField>
          <div v-if="selectedTipe.value == 'cash'">
            <VBtn @click="addNominal(1000)">1000</VBtn>
            <VBtn @click="addNominal(2000)">2000</VBtn>
            <VBtn @click="addNominal(5000)">5000</VBtn>
            <VBtn @click="addNominal(10000)">10000</VBtn>
            <VBtn @click="addNominal(20000)">20000</VBtn>
            <VBtn @click="addNominal(50000)">50000</VBtn>
            <VBtn @click="addNominal(100000)">100000</VBtn>
          </div>
          <VBtn @click="onCloseClick">close</VBtn>
          <VBtn @click="onCancelClick">cancel</VBtn>
          <VBtn @click="onPaidClick">bayar</VBtn>
        </VForm>
      </VCardText>
    </VCard>
  </VDialog>
</template>

<script setup>
import { ref, watch } from 'vue'
import * as mdiIcon from '@mdi/js'

const props = defineProps({
  title: String,
  show: Boolean,
  total: Number,
  items: Array
})
const emit = defineEmits(['onHide', 'submit', 'onCancel'])
// const rules = {
//   required: (value) => !!value || 'This field is required',
//   email: (v) => /.+@.+\..+/.test(v) || 'Must be a valid email'
// }

const { axiosPost } = useAppStore()

const showDialog = ref(false)
const showRef = ref(false)
const selectedTipe = ref(null)
const status = ref(null)

const paid = ref(0)

const tipePayments = [
  { label: 'cash', value: 'cash', ref: false },
  { label: 'debit', value: 'debit', ref: true },
  { label: 'Kredit', value: 'credit', ref: true }
]

function onAfterLeave() {
  if (!status.value) emit('onHide', { status: 'hide' })
}

function addNominal(nominal) {
  paid.value += nominal
}

function onCloseClick() {
  status.value = null
  showDialog.value = false
}

function onPaidClick() {
  status.value = 'paid'
  showDialog.value = false
  const data = {
    status: status.value,
    tipePembayaran: selectedTipe.value.value,
    paid: paid.value,
    total: props.total,
    items: []
  }
  console.log('props.items', props.items)
  for (const item of props.items) {
    data.items.push({
      ...item,
      subtotal: item.hargaSatuan * item.quantity
    })
    // console.log("item", );
    // data.items.push({
    //   idBarang: item.raw.id,
    //   nama: item.raw.nama,
    //   hargaSatuan: item.raw.hargaSatuan,
    //   quantity: item.raw.quantity,
    //   subtotal: item.raw.hargaSatuan * item.raw.quantity
    // })
  }
  // data.items = props.items;

  axiosPost('/penjualan', data, { auth: true }).then((res) => {
    console.log(res)
  })
  emit('onHide', { status: status.value })
}

function onCancelClick() {
  status.value = 'cancel'
  showDialog.value = false

  emit('onCancel', { status: status.value })
}

const Kembalian = computed(() => {
  if (selectedTipe.value.value === 'cash') {
    return paid.value - props.total
  }
  return 0
})

watch(
  () => props.show,
  (newVal) => {
    showDialog.value = newVal
    // if(newVal) {
    //   paid.value = 0
    // }
  }
)

watch(
  () => props.total,
  (newVal) => {
    showDialog.value = newVal
  }
)

watch(selectedTipe, (newVal) => {
  showRef.value = newVal.ref
  if (selectedTipe.value.ref === true) {
    paid.value = props.total
  } else {
    paid.value = 0
  }
})

watch(showDialog, (newVal) => {
  if (newVal) {
    showRef.value = false
    selectedTipe.value = tipePayments[0]
    status.value = null
    paid.value = 0
  }
})
</script>
